    <div>
      <div
        id="tbh0"
        @click="show(0)"
        style="
          float: left;
          width: 150px;
          height: 40px;
          line-height: 40px;
          text-align: center;
          border: 1px solid #ccc;
          background: #efefef;
          font-size: 14px;
        "
      >
        (音/视)频文件播放
      </div>
    </div>

    <div id="tb0">
      <table
        width="98%"
        border="0"
        align="center"
        cellpadding="0"
        cellspacing="0"
      >
        <tr>
          <td bgcolor="#0A7E81">
            <table
              width="100%"
              border="0"
              cellpadding="0"
              cellspacing="0"
              @click="executeOpenFileByAAC()"
            >
              <tr>
                <td width="26%" height="60" align="right">
                  <img
                    :src="requireImg('images/media_titleIcon.png')"
                    width="55"
                    height="50"
                  />
                </td>
                <td width="74%">
                  <span class="STYLE1">　请选择要播放的文件</span>
                </td>
              </tr>
            </table>
          </td>
        </tr>
        <tr>
          <td><span class="STYLE6"> </span></td>
        </tr>
        <tr height="30">
          <td height="30" width="350">
            文件路径:<input
              name="fileAACHTMLI"
              type="text"
              class="bk"
              id="fileAACHTMLI"
              size="30"
              readonly="true"
            />
          </td>
        </tr>
        <tr width="350" height="380">
          <td align="center" valign="top">
            <video
              id="fileAACHTML"
              width="350"
              height="380"
              type="video/mp4"
              src=""
              controls
            ></video>
          </td>
        </tr>
      </table>
    </div>
  </div>
</template>

<script>
export default {
  name: "media", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      //判断是否为空[可根据此为标志位]
      //null:表示未播放
      //非空:正在播放
      thatMedia: null,
      mediaTimer: null,
      oldPath: "",
      //全局变量，用于开始和停止录制
      mediaRec: null,
      oldAACPath: "",
      oldMediaPath: "",
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    //由于在Android平台上和在IOS平台上打开文件执行的不一样，所以在这边加上了具体的平台判断
    //IOS:调用照片库，返回文件
    //Android:调用自己写插件，通过自己写的插件，调用自己写的原生浏览文件的一个Activity浏览文件返回指定路径
    executeOpenFile() {
      console.log(" executeOpenFile()-->start");
      if (!deviceReady) {
        console.log("Cordova is not ready,return");
        return;
      }
      //获取设备平台
      var devicePlatform = device.platform;
      console.log(" executeOpenFile() ,devicePlatform:" + devicePlatform);
      if ("iOS" == devicePlatform) {
        this.executeOpenFileByIOS();
      } else if ("Android" == devicePlatform) {
        this.executeOpenFileByAndroid();
      } else {
        console.log("invaiate platform");
      }
    },

    //为Android平台时打开文件执行的操作[自己写的插件，打开自己写的本地应用此应用显示系统文件信息，用户选择后带回文件信息]
    executeOpenFileByAndroid() {
      console.log("executeOpenFileByAndroid()-->start");
      mam.navigator.forward.goToFileExplorer(
        successCallback,
        null,
        DLForwardConstants.FileExplorer.ACTION_OPEN_MEDIA_FILE
      );
      function successCallback(filePath) {
        console.log("successCallback() filePath:" + filePath);
        document.getElementById("file").value = filePath;
      }

      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },

    //为IOS平台时，执行打开文件时操作
    executeOpenFileByIOS() {
      alert("executeOpenFileByIOS()-->start");
      mam.navigator.selectMusic.getLocalFile(successCallback, errorCallback);
      function successCallback(filePath) {
        console.log("successCallback() filePath:" + filePath);
        document.getElementById("file").value = filePath;
      }

      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },

    playAudio() {
      //判断cordova环境是否加载好,如果未加载好，直接退出
      if (!deviceReady) {
        console.log("Cordova is not ready,return");
        return;
      }

      //清空错误信息
      document.getElementById("errorMsg").value = "";

      var path = document.getElementById("file").value;

      if ("" == path) {
        document.getElementById("errorMsg").value = "播放路径为空";
        return;
      }

      //播放对象为null 或 选择新的播放文件时new,其他情况保持现有对象，用于暂停功能
      if (null == this.thatMedia || this.oldPath != path) {
        this.thatMedia = new Media(path, onSuccess, onError, onStatusCallback);
        this.oldPath = path;
      }

      //设定音量[取值范围从0.0-1.0之间,输入字符到底层需要类型转换的，如果不符合要求类型转换会错误]
      this.thatMedia.setVolume("1.0");
      var totalProgress = this.thatMedia.getDuration();
      document.getElementById("totalProgress").value = totalProgress + "秒";

      this.thatMedia.play();
      //另个对象执行播放时，定时器停止
      if (null != this.mediaTimer) {
        clearInterval(this.mediaTimer);
        this.mediaTimer = null;
      }

      //设定定时器,每隔n毫秒执行一次其中回调
      this.mediaTimer = setInterval(function () {
        console.log("timer...");
        if (null == this.thatMedia) {
          return;
        }
        this.thatMedia.getCurrentPosition(
          // success callback
          function (position) {
            if (position > -1) {
              //console.log((position) + " sec");
              document.getElementById("currentProgress").value =
                position + "秒";
            }
          },
          // error callback
          function (e) {
            console.log("Error getting pos=" + e);
          }
        );
      }, 1000);

      //播放成功的回调
      function onSuccess() {
        console.log("play success...");
      }

      //播放失败的回调[根据错误码显示错误消息]
      function onError(mediaError) {
        var errorCode = mediaError.code;
        //获取错误消息
        var errorMsg = showMediaErrorMsg(errorCode);
        this.thatMedia = null;
        document.getElementById("errorMsg").value = errorMsg;
      }

      //根据底层的错误码,返回错误消息
      function showMediaErrorMsg(errorCode) {
        var errorMsg = "";
        if (MediaError.MEDIA_ERR_ABORTED == errorCode) {
          errorMsg = "终止";
        } else if (MediaError.MEDIA_ERR_NETWORK == errorCode) {
          errorMsg = "网络错误";
        } else if (MediaError.MEDIA_ERR_DECODE == errorCode) {
          errorMsg = "解码错误";
        } else if (MediaError.MEDIA_ERR_NONE_SUPPORTED == errorCode) {
          errorMsg = "没有被提供";
        }
        return errorMsg;
      }

      function onStatusCallback(result) {
        console.log("onStatusCallback() result:" + result);
        document.getElementById("currentStatus").value = showStatus(result);
      }

      //显示播放的状态
      function showStatus(result) {
        var r = "";
        if (result == Media.MEDIA_NONE) {
          r = "none";
        } else if (result == Media.MEDIA_STARTING) {
          r = "开始";
        } else if (result == Media.MEDIA_RUNNING) {
          r = "正在播放";
        } else if (result == Media.MEDIA_PAUSED) {
          r = "暂停";
        } else if (result == Media.MEDIA_STOPPED) {
          r = "停止";
        }
        return r;
      }
    },

    //暂停播放
    pauseAudio() {
      //判断cordova环境是否加载好,如果未加载好，直接退出
      if (!deviceReady) {
        console.log("pauseAudio()  Cordova is not ready,return");
        return;
      }

      if (this.thatMedia) {
        this.thatMedia.pause();
      }
    },

    //停止播放
    //停止播放时，thatMedia被设定为空
    stopAudio() {
      //判断cordova环境是否加载好,如果未加载好，直接退出
      if (!deviceReady) {
        console.log("stopAudio()  Cordova is not ready,return");
        return;
      }

      if (this.thatMedia) {
        this.thatMedia.stop();
        //释放媒体资源
        this.thatMedia.release();
        this.thatMedia = null;
      }

      //计时器停止
      if (null != this.mediaTimer) {
        clearInterval(this.mediaTimer);
        this.mediaTimer = null;
      }
    },

    //清除掉其中的数据
    executeClear() {
      //清除文件输入中的信息
      document.getElementById("file").value = "";
    },

    //清除所有信息
    //1:文件输入框
    //2:状态框
    //3:错误消息框
    executeAllClear() {
      //清除文件输入中的信息
      document.getElementById("file").value = "";
      document.getElementById("currentStatus").value = "";
      document.getElementById("errorMsg").value = "";
    },

    //在录制界面创建临时要生产的文件路径
    createTempFilePath() {
      //获取当前时间[时间戳对象]
      var timeStamp = Date.parse(new Date());
      //获取设备平台
      var devicePlatform = device.platform;
      var path = "";
      if ("iOS" == devicePlatform) {
        path = "record_" + timeStamp + ".wav";
      } else if ("Android" == devicePlatform) {
        path = "record_" + timeStamp + ".aac";
      } else {
        console.log("invaiate devicePlatform...");
      }
      document.getElementById("recordFile").value = path;
    },

    /***********************************播放播放音频      开始*******************************/

    //为Android平台时打开文件执行的操作[自己写的插件，打开自己写的本地应用此应用显示系统文件信息，用户选择后带回文件信息]

    executeOpenFileByAAC() {
      console.log(" executeOpenFile()-->start");
      if (!deviceReady) {
        console.log("Cordova is not ready,return");
        return;
      }
      //获取设备平台
      var devicePlatform = device.platform;
      console.log(" executeOpenFile() ,devicePlatform:" + devicePlatform);
      if ("iOS" == devicePlatform) {
        this.executeOpenFileByIOSByPlayAAC();
      } else if ("Android" == devicePlatform) {
        console.log("Android");
        this.executeOpenFileByAndroidByPlayAAC();
      } else {
        console.log("invaiate platform");
      }
    },

    executeOpenFileByAndroidByPlayAAC() {
      console.log("executeOpenFileByAndroidPlayAAC()-->start");
      mam.navigator.forward.goToFileExplorer(
        successCallbackPlayAAC,
        null,
        DLForwardConstants.FileExplorer.ACTION_OPEN_MEDIA_FILE
      );
      function successCallbackPlayAAC(filePathPlayAAC) {
        console.log("successCallback() filePathPlayAAC:" + filePathPlayAAC);

        document.getElementById("fileAACHTMLI").value = filePathPlayAAC;
        document.getElementById("fileAACHTML").src = filePathPlayAAC;

        console.log(document.getElementById("fileAACHTML").src);
      }

      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },
    //为IOS平台时，执行打开文件时操作
    executeOpenFileByIOSByPlayAAC() {
      alert("executeOpenFileByIOSByPlayAAC()-->start");
      //mam.navigator.selectMusic.getLocalFile(successCallbackByPlayAAC,errorCallbackByPlayAAC);
      mam.navigator.selectMusic.getLocalFile(
        successCallbackByPlayAAC,
        errorCallbackByPlayAAC
      );
      function successCallbackByPlayAAC(filePathByPlayAAC) {
        document.getElementById("fileAACHTMLI").value = filePathByPlayAAC;
        document.getElementById("fileAACHTML").src = filePathByPlayAAC;

        console.log(document.getElementById("fileAACHTML").src);
      }

      function errorCallbackByPlayAAC(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },

    playAAC() {
      //判断cordova环境是否加载好,如果未加载好，直接退出
      if (!deviceReady) {
        console.log("Cordova is not ready,return");
        return;
      }

      var pathAAC = document.getElementById("fileAAC").value;

      console.log("playMedia  " + pathAAC);
      // Play the audio file at url
      var my_AAC = new Media(
        pathAAC,
        // success callback
        function () {
          console.log("playAudio():Audio Success");
          console.log("playAudio():Audio Success");
        },
        // error callback
        function (err) {
          console.log("playAudio():Audio Error: " + err);
          console.log("playAudio():Audio Error: " + err);
        }
      );
      // Play audio
      console.log("playAudio");
      my_AAC.play();
    },

    pauseAAC() {},

    stopAAC() {},

    /***********************************播放音频     结束*******************************/

    /***********************************播放视频     开始*******************************/

    //为Android平台时打开文件执行的操作[自己写的插件，打开自己写的本地应用此应用显示系统文件信息，用户选择后带回文件信息]

    executeOpenFileByMedia() {
      console.log(" executeOpenFile()-->start");
      if (!deviceReady) {
        console.log("Cordova is not ready,return");
        return;
      }
      //获取设备平台
      var devicePlatform = device.platform;
      console.log(" executeOpenFile() ,devicePlatform:" + devicePlatform);
      if ("iOS" == devicePlatform) {
        this.executeOpenFileByIOSByMedia();
      } else if ("Android" == devicePlatform) {
        console.log("Android");
        this.executeOpenFileByAndroidByPlayMedia();
      } else {
        console.log("invaiate platform");
      }
    },

    //为IOS平台时，执行打开文件时操作
    executeOpenFileByIOSByMedia() {
      console.log("executeOpenFileByIOSByMedia()-->start");
      mam.navigator.selectMusic.getLocalFile(
        successCallbackByMedia,
        errorCallbackByMedia
      );
      function successCallbackByMedia(filePathByMedia) {
        document.getElementById("fileAACHTMLI").value = filePathByMedia;
        document.getElementById("fileAACHTML").src = filePathByMedia;

        console.log(document.getElementById("fileAACHTML").src);
      }

      function errorCallbackByMedia(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },

    executeOpenFileByAndroidByPlayMedia() {
      console.log("executeOpenFileByAndroidPlayMedia()-->start");
      mam.navigator.forward.goToFileExplorer(
        successCallbackPlayMedia,
        null,
        DLForwardConstants.FileExplorer.ACTION_OPEN_MEDIA_FILE
      );
      function successCallbackPlayMedia(filePathPlayMedia) {
        console.log("successCallback() filePathPlayMedia:" + filePathPlayMedia);

        document.getElementById("fileMediaHTMLI").value = filePathPlayMedia;
        document.getElementById("fileMediaHTML").src = filePathPlayMedia;

        console.log(document.getElementById("fileMediaHTML").src);
      }

      function errorCallback(msg) {
        console.log("errorCallback() msg:" + msg);
      }
    },

    playMedia() {
      //判断cordova环境是否加载好,如果未加载好，直接退出
      if (!deviceReady) {
        console.log("Cordova is not ready,return");
        return;
      }

      //清空错误信息
      //	document.getElementById('errorMsgMedia').value = "";

      var pathMedia = document.getElementById("fileMedia").value;

      //	if('' == pathMedia){
      //document.getElementById('errorMsgMedia').value = "播放路径为空";
      //		return;
      //	}

      //播放对象为null 或 选择新的播放文件时new,其他情况保持现有对象，用于暂停功能
      //	if(null == thatMedia || oldPath != path){
      //	thatMedia = new Media(path, onSuccess, onError,onStatusCallback);
      //	oldPath = path;
      //		}

      console.log("playMedia  " + pathMedia);
      // Play the audio file at url
      var my_media = new Media(
        pathMedia,
        // success callback
        function () {
          console.log("playAudio():Audio Success");
          console.log("playAudio():Audio Success");
        },
        // error callback
        function (err) {
          console.log("playAudio():Audio Error: " + err);
          console.log("playAudio():Audio Error: " + err);
        }
      );
      // Play audio
      console.log("playAudio");
      my_media.play();
    },

    pauseMedia() {},

    stopMedia() {},

    /***********************************播放视频     结束*******************************/

    //开始录制音频
    startRecordAudio() {
      var path;

      if (!deviceReady) {
        console.log("startRecordAudio()  Cordova is not ready,return");
        var result = "cordova 环境没有准备好,退出...";
        this.printOnResultMsg2(result);
        return;
      }

      //判断路径，路径为空直接返回
      path = document.getElementById("recordFile").value;
      if ("" == path) {
        var result = "startRecordAudio()  Cordova is not ready,return";
        console.log(result);
        this.printOnResultMsg2(result);
        return;
      }

      //判断原来的有没释放掉,没释放的话这边释放[用户连续多次点击，会释放掉原来的的重新初始化]
      if (null != this.mediaRec) {
        this.mediaRec.stopRecord();
        this.mediaRec.release();
        this.mediaRec = null;
      }

      //点击录制按钮录制时，先清除掉"当前状态"文本框,"执行结果文本框"
      document.getElementById("currentStatus2").value = "";
      //此组件上清空
      this.printOnResultMsg2("");

      //初始化对象
      this.mediaRec = new Media(
        path,
        successCallback,
        errorCallback,
        onStatusCallback
      );
      //开始录制
      this.mediaRec.startRecord();

      //录制成功的回调
      function successCallback() {
        console.log("recordAudio():Audio Success");
        var result = "录制成功,录制后文件存放在sd卡下,文件名为:" + path;
        this.printOnResultMsg2(result);
      }

      //录制失败的回调
      function errorCallback(mediaError) {
        console.log("recordAudio():Audio Error: " + mediaError.code);
        var result =
          "录制操作发生错误，错误码 " +
          mediaError.code +
          ",错误原因为:" +
          mediaError.message;
        this.printOnResultMsg2(result);
      }

      //状态改变时发生的回调
      function onStatusCallback(result) {
        console.log("onStatusCallback() result:" + result);
        document.getElementById("currentStatus2").value = showStatus(result);
      }

      //显示录制操作的状态
      function showStatus(result) {
        var r = "";
        if (result == Media.MEDIA_NONE) {
          r = "none";
        } else if (result == Media.MEDIA_STARTING) {
          r = "开始";
        } else if (result == Media.MEDIA_RUNNING) {
          r = "正在录制";
        } else if (result == Media.MEDIA_PAUSED) {
          r = "暂停";
        } else if (result == Media.MEDIA_STOPPED) {
          r = "录音完成";
        }
        return r;
      }
    },

    printOnResultMsg2(resultMsg) {
      document.getElementById("resultMsg2").value = resultMsg;
    },

    //停止录制
    stopRecordAudio() {
      //环境未加载好，这边直接退出
      if (!deviceReady) {
        console.log("stopRecordAudio()  Cordova is not ready,return");
        return;
      }

      console.log(
        "stopRecordAudio()--(null != mediaRec):" + (null != this.mediaRec)
      );

      //判断对象是否存在，如果存在则释放
      if (null != this.mediaRec) {
        this.mediaRec.stopRecord();
        this.mediaRec.release();
        this.mediaRec = null;
      }
    },

    //在录制面板上，清除选中的录制的文件
    executeClearOnTabRecord() {
      document.getElementById("recordFile").value = "";
    },

    //在录制面板上清除所有信息
    //1:文件输入框
    //2:状态框
    //3:错误消息框
    executeAllClearOnTabRecord() {
      //清除文件输入中的信息
      document.getElementById("recordFile").value = "";
      document.getElementById("currentStatus2").value = "";
      //清除其中的数据
      this.printOnResultMsg2("");
    },

    //开始录制音频_新插件
    newstartRecordAudio() {
      var path;

      if (!deviceReady) {
        console.log("startRecordAudio()  Cordova is not ready,return");
        var result = "cordova 环境没有准备好,退出...";
        this.printOnResultMsg2(result);
        return;
      }

      //点击录制按钮录制时，先清除掉"当前状态"文本框,"执行结果文本框"
      document.getElementById("currentStatus2").value = "";
      //此组件上清空
      this.printOnResultMsg2("");

      //开始录制
      console.log("aac 音频录制 开始 ");
      mam.navigator.audio.startRecordAudio(successCallback, errorCallback);

      //录制成功的回调
      function successCallback(data) {
        console.log("aac 音频录制 中 ");
      }

      //录制失败的回调
      function errorCallback(data) {
        console.log("recordAudio():Audio Error: " + data);
        var result = "录制操作发生错误，错误码 " + data + ",错误原因为:" + data;
        this.printOnResultMsg2(result);
      }

      //状态改变时发生的回调
      function onStatusCallback() {
        document.getElementById("currentStatus2").value = "正在录制";
      }
    },
    //停止录制_新插件
    newstopRecordAudio() {
      //环境未加载好，这边直接退出
      if (!deviceReady) {
        console.log("stopRecordAudio()  Cordova is not ready,return");
        return;
      }

      //停止录制
      console.log("aac 音频录制 停止 ");
      mam.navigator.audio.finishRecordAudio(successCallback, errorCallback);

      //录制成功的回调
      function successCallback(data) {
