      }

      //录制失败的回调
      function errorCallback(data) {
        console.log("recordAudio():Audio Error: " + data);
        var result = "录制操作发生错误，错误码 " + data + ",错误原因为:" + data;
        this.printOnResultMsg2(result);
      }
    },

    /**

		录制 音频 aac格式
		开始录音
		参数说明：
			onSuccess	成功回调
			onError		失败回调
			filePath	文件路径  (无意义 待优化)

	**/
    startRecordAudio() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("startRecordAudio");
      var filePath = "/aacUrl";
      //使用这边调用可以获取本地通讯录
      mam.navigator.audio.startRecordAudio(
        startonSuccess,
        startonError,
        filePath
      );

      function startonSuccess(data) {
        console.log("onSuccess() data:" + data);
      }

      //参数为string类型
      function startonError(data) {
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },
    /**

	录制 音频 aac格式
	结束录音
	参数说明：
		onSuccess	成功回调
		onError		失败回调
	**/
    finishRecordAudio() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("finishRecordAudio");
      mam.navigator.audio.finishRecordAudio(finishonSuccess, finishonError);

      function finishonSuccess(data) {
        document.getElementById("fileAACUrl").value = data;

        document.getElementById("aacAudio").src = data;
        console.log("onSuccess() data:" + data);
      }
      function finishonError(data) {
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },

    //标签切换函数
    show(v) {
      if (v == 0) {
        $("#tb0").show();
        $("#tbh0").css("background", "#efefef");
        $("#tb1").hide();
        $("#tbh1").css("background", "");
        $("#tb2").hide();
        $("#tbh2").css("background", "");
        $("#tb3").hide();
        $("#tbh3").css("background", "");
      } else if (v == 3) {
        $("#tb3").show();
        $("#tbh3").css("background", "#efefef");
        $("#tb1").hide();
        $("#tbh1").css("background", "");
        $("#tb0").hide();
        $("#tbh0").css("background", "");
        $("#tb2").hide();
        $("#tbh2").css("background", "");
      }
    },
